  Object.keys(jsonObj).sort().forEach(key => {
    ordered[key] = jsonObj[key];
  });
  return ordered;
}

const sanitizeWorkflow = (workflowObj) => {
  if (!workflowObj) return workflowObj;
  let str = JSON.stringify(workflowObj);
  // Redact OpenRouter API keys (sk-or-v1-...)
  str = str.replace(/sk-or-v1-[a-fA-F0-9]+/g, "[REDACTED_OPENROUTER_KEY]");
  // Redact Anthropic API keys (sk-ant-api03-...)
  str = str.replace(/sk-ant-api03-[a-zA-Z0-9-_]+/g, "[REDACTED_ANTHROPIC_KEY]");
  // Redact standard OpenAI-like keys (sk-...)
  str = str.replace(/\bsk-[a-zA-Z0-9]{32,64}\b/g, "[REDACTED_OPENAI_KEY]");
  // Redact ElevenLabs and other sk_ API keys
  str = str.replace(/\bsk_[a-zA-Z0-9]{32,64}\b/g, "[REDACTED_ELEVENLABS_KEY]");
  // Redact RapidAPI Key (50 chars alphanumeric containing "cmsh", standard pattern)
  str = str.replace(/\b[a-zA-Z0-9]{9}cmsh[a-zA-Z0-9]{37}\b/g, "[REDACTED_RAPIDAPI_KEY]");
  // Redact Telegram bot tokens (e.g. 123456789:ABCdefGh...)
  str = str.replace(/\b\d{8,11}:[a-zA-Z0-9_-]{35}\b/g, "[REDACTED_TELEGRAM_TOKEN]");
  // Redact Creatomate and other 96-char keys
  str = str.replace(/\b[a-zA-Z0-9]{96}\b/g, "[REDACTED_CREATOMATE_KEY]");
  // Redact Pexels and other 56-char keys
  str = str.replace(/\b[a-zA-Z0-9]{56}\b/g, "[REDACTED_PEXELS_KEY]");
  return JSON.parse(str);
}

// Check if file returned with content
if (Object.keys($input.all()[0].json).includes("content")) {
  // Decode base64 content and parse JSON
  const origWorkflow = sanitizeWorkflow(JSON.parse(Buffer.from($input.all()[0].json.content, 'base64').toString()));
  const n8nWorkflow = sanitizeWorkflow($input.all()[1].json);

  // Order JSON objects
