  }
  $input.all()[0].json.content_decoded = orderedOriginal;

} else {
  // Order JSON object
  const n8nWorkflow = sanitizeWorkflow($input.all()[1].json);
  const orderedActual = orderJsonKeys(n8nWorkflow);

  // Proper formatting
  $input.all()[0].json.github_status = "new";
  $input.all()[0].json.n8n_data_stringy = JSON.stringify(orderedActual, null, 2);
}

// Return items
return $input.all();

const data = $input.first().json;
const VOICE = 'Josh';
const TEMPLATE_ID = ($('API Config').first().json.CREATOMATE_TEMPLATE_ID || '').trim();

if (!TEMPLATE_ID) throw new Error('CREATOMATE_TEMPLATE_ID not set in API Config node.');

const modifications = {};

data.scenes.forEach((scene, i) => {
  const n = i + 1;

  modifications[`Narration-${n}.text`]    = scene.narration;
  modifications[`Narration-${n}.voice`]   = VOICE;
  modifications[`Background-${n}.source`] = scene.video_url;

  const raw = (scene.narration.match(/[^.!?]+[.!?]+/) || [scene.narration])[0].trim();
  modifications[`Caption-${n}.text`] = raw.length > 90 ? raw.substring(0, 87) + '...' : raw;
});

modifications['Outro-Moral.text'] = data.moral_question;

return [{
  json: {
    template_id:    TEMPLATE_ID,
    modifications,
    topic:          data.topic,
    title:          data.title,
    description:    data.description,
    tags:           data.tags,
    tags_string:    data.tags_string,
    thumbnail_text: data.thumbnail_text,
    moral_question: data.moral_question
  }
}];

