}

const render = JSON.parse(result.body);

return [{
  json: {
    ...meta,
    shorts_render_status: render.status,
    shorts_render_url: render.url || null
  }
}];

const raw = $input.first().json;
const topic = $('Prepare Claude Request').first().json.topic;

if (!raw.content || !raw.content[0]) {
  throw new Error('Unexpected Claude response: ' + JSON.stringify(raw).substring(0, 200));
}

const rawText = raw.content[0].text.trim();

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

let script;
try {
  script = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + ' | Raw: ' + cleaned.substring(0, 300));
}

if (!script.scenes || !Array.isArray(script.scenes)) {
  throw new Error('Invalid script: missing scenes array');
}

script.scenes = script.scenes.slice(0, 9);

return [{
  json: {
    topic,
    title: script.title,
    description: script.description,
    tags: script.tags || ['betrayal','revenge','story'],
    tags_string: (script.tags || ['betrayal','revenge','story']).join(','),
    thumbnail_text: script.thumbnail_text || script.title.substring(0, 40),
    moral_question: script.moral_question || 'Was this the right thing to do?',
    scenes: script.scenes,
    total_scenes: script.scenes.length
  }
}];

// ── Generate Voice Audio via ElevenLabs API ──────────────────────────────────
// Calls ElevenLabs directly, returns binary MP3 + all scene metadata
// This approach bypasses Creatomate's ElevenLabs integration entirely

const https = require('https');
const data = $input.first().json;
const ELEVENLABS_API_KEY = ($('API Config').first().json.ELEVENLABS_API_KEY || '').trim();
const VOICE_ID = 'TxGEqnHWrfWFTfGW9XjX'; // Josh — change to your preferred voice ID

if (!ELEVENLABS_API_KEY || ELEVENLABS_API_KEY === 'YOUR_ELEVENLABS_API_KEY_HERE') {
  throw new Error('ELEVENLABS_API_KEY not set in API Config node.');
}

// Combine all scene narrations into one continuous story
const fullText = data.scenes.map(s => s.narration).join(' ');

const requestBody = JSON.stringify({
  text: fullText,
  model_id: 'eleven_multilingual_v2',
  voice_settings: {
    stability: 0.5,
    similarity_boost: 0.8,
    style: 0.3,
    use_speaker_boost: true
  }
});

const bodyBuffer = Buffer.from(requestBody, 'utf8');

const result = await new Promise((resolve, reject) => {
  const chunks = [];
  const req = https.request({
    hostname: 'api.elevenlabs.io',
    path: `/v1/text-to-speech/${VOICE_ID}`,
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'xi-api-key': ELEVENLABS_API_KEY,
      'Content-Length': bodyBuffer.length
    }
  }, (res) => {
    res.on('data', chunk => chunks.push(chunk));
    res.on('end', () => resolve({
      statusCode: res.statusCode,
      contentType: res.headers['content-type'] || 'audio/mpeg',
      buffer: Buffer.concat(chunks)
    }));
  });
  req.on('error', reject);
  req.write(bodyBuffer);
  req.end();
});

if (result.statusCode >= 400) {
  throw new Error('ElevenLabs ' + result.statusCode + ': ' + result.buffer.toString().substring(0, 300));
}

const filename = 'kd-voice-' + Date.now() + '.mp3';

return [{
  json: {
    ...data,
    audio_filename: filename
  },
  binary: {
    audio: {
      data: result.buffer.toString('base64'),
      mimeType: 'audio/mpeg',
      fileName: filename,
      fileExtension: 'mp3'
    }
  }
}];

// Merge Drive file ID with scene data, construct public audio URL
const driveResult = $input.first().json;
const sceneData = $('Generate Voice Audio').first().json;

const fileId = $('Upload Voice to Drive').first().json.id;
if (!fileId) throw new Error('No Drive file ID returned: ' + JSON.stringify(driveResult).substring(0, 200));

// Public direct-download URL format for Google Drive
const audioUrl = 'https://drive.google.com/uc?export=download&id=' + fileId;

return [{
  json: {
    ...sceneData,
    audio_url: audioUrl,
    audio_file_id: fileId
  }
}];
